import re

# 输入获取
arr = input().split()
reg = input().replace("*", "(.*)")


# 算法入口
def getResult():
    c = re.compile(f"^{reg}$")

    ans = []
    for i in range(len(arr)):
        if c.match(arr[i]):
            ans.append(i)

    if len(ans) == 0:
        return "-1"
    else:
        return ",".join(map(str, ans))


# 算法调用
print(getResult())
